arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 0);
ITransformer? trainedModel = null;
PredictionEngine<CustomerData, ChurnPrediction>? predictionEngine = null;

var csvPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
if (!File.Exists(csvPath))
    csvPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "customers.csv");

app.MapGet("/", () => "ChurnPredictor API — POST /train then POST /predict");

app.MapPost("/train", () =>
{
    var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
        csvPath, hasHeader: true, separatorChar: ',');

    var pipeline = mlContext.Transforms.CustomMapping<CustomerData, ChurnLabel>(
            (input, output) => output.Label = input.Churned == "Yes",
            contractName: "ChurnMapping")
        .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(CustomerData.Age),
            nameof(CustomerData.Income),
            nameof(CustomerData.PurchaseHistory),
            "RegionEncoded"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.FastTree(
            labelColumnName: "Label", featureColumnName: "Features",
            numberOfLeaves: 4, minimumExampleCountPerLeaf: 1,
            numberOfTrees: 50, learningRate: 0.1));

    trainedModel = pipeline.Fit(dataView);
    predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(trainedModel);

    var predictions = trainedModel.Transform(dataView);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

    return Results.Ok(new
    {
        Message = "Model trained",
        Accuracy = metrics.Accuracy,
        AUC = metrics.AreaUnderRocCurve,
        F1Score = metrics.F1Score
    });
});

app.MapPost("/predict", (CustomerInput input) =>
{
    if (predictionEngine is null)
        return Results.BadRequest(new { Error = "Train the model first by calling POST /train" });

    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
        Churned = ""
    };

    var result = predictionEngine.Predict(data);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score
    });
});

app.Run();

// ── Data models ──────────────────────────────────────────────

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class ChurnLabel
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

